import { ClientError, ServerError, Status } from 'nice-grpc';
import { BatchObjectsRequest, BatchStreamRequest, } from '../proto/v1/batch.js';
import { WeaviateBatchError, WeaviateBatchStreamError, WeaviateDeleteManyError, WeaviateInsufficientPermissionsError, WeaviateRequestTimeoutError, } from '../errors.js';
import { BatchDeleteRequest } from '../proto/v1/batch_delete.js';
import Base from './base.js';
import { isAbortError } from 'abort-controller-x';
import { retryOptions } from './retry.js';
export default class Batcher extends Base {
    static use(connection, collection, metadata, timeout, consistencyLevel, tenant) {
        return new Batcher(connection, collection, metadata, timeout, consistencyLevel, tenant);
    }
    withStream = (reqs) => this.callStream(reqs);
    withDelete = (args) => this.callDelete(BatchDeleteRequest.fromPartial(args));
    withObjects = (args) => this.callObjects(BatchObjectsRequest.fromPartial(args));
    async *callStream(reqs) {
        const consistencyLevel = this.consistencyLevel;
        async function* generate() {
            yield BatchStreamRequest.create({ start: { consistencyLevel } });
            for await (const req of reqs) {
                yield req;
            }
        }
        try {
            for await (const res of this.connection.batchStream(generate(), { metadata: this.metadata })) {
                yield res;
            }
        }
        catch (err) {
            if (err instanceof ClientError) {
                throw new WeaviateBatchStreamError(err.message);
            }
            throw err;
        }
    }
    callDelete(message) {
        return this.sendWithTimeout((signal) => this.connection.batchDelete({
            ...message,
            collection: this.collection,
            consistencyLevel: this.consistencyLevel,
            tenant: this.tenant,
        }, {
            metadata: this.metadata,
            signal,
        })).catch((err) => {
            if (err instanceof ServerError && err.code === Status.PERMISSION_DENIED) {
                throw new WeaviateInsufficientPermissionsError(7, err.message);
            }
            if (isAbortError(err)) {
                throw new WeaviateRequestTimeoutError(`timed out after ${this.timeout}ms`);
            }
            throw new WeaviateDeleteManyError(err.message);
        });
    }
    callObjects(message) {
        return this.sendWithTimeout((signal) => this.connection
            .batchObjects({
            ...message,
            consistencyLevel: this.consistencyLevel,
        }, {
            metadata: this.metadata,
            signal,
            ...retryOptions,
        })
            .catch((err) => {
            if (err instanceof ServerError && err.code === Status.PERMISSION_DENIED) {
                throw new WeaviateInsufficientPermissionsError(7, err.message);
            }
            if (isAbortError(err)) {
                throw new WeaviateRequestTimeoutError(`timed out after ${this.timeout}ms`);
            }
            throw new WeaviateBatchError(err.message);
        }));
    }
}
